def admin_panel_reload_paths():
    paths = [
        pathlib.Path(__file__).resolve(),
        CODE_ROOT / "admin" / "community_rewards.py",
        CODE_ROOT / "admin" / "moderation.py",
        CODE_ROOT / "admin" / "base_creator.py",
        CODE_ROOT / "admin" / "base_retirement.py",
        CODE_ROOT / "admin" / "gameplay_presets.py",
        CODE_ROOT / "admin" / "command_console.py",
        CODE_ROOT / "admin" / "federated_auth.py",
        CODE_ROOT / "admin" / "cosmetics_admin.py",
        CODE_ROOT / "admin" / "progression_admin.py",
        CODE_ROOT / "admin" / "audit_ledger.py",
        CODE_ROOT / "admin" / "restore_drill.py",
        CODE_ROOT / "admin" / "operational_slo.py",
        OPERATIONAL_SLO_POLICY,
        CODE_ROOT / "admin" / "capacity_intelligence.py",
        CAPACITY_INTELLIGENCE_POLICY,
        CODE_ROOT / "admin" / "desired_state.py",
        DESIRED_STATE_POLICY,
        CODE_ROOT / "admin" / "change_intelligence.py",
        CHANGE_INTELLIGENCE_POLICY,
        CODE_ROOT / "admin" / "deployment_assurance.py",
        GAMEPLAY_PRESETS_FILE,
        COSMETIC_CATALOG_FILE,
        CODE_ROOT / "admin" / "access_control.py",
        CODE_ROOT / "admin" / "change_approvals.py",
        CODE_ROOT / "admin" / "change_contracts.py",
        CODE_ROOT / "scripts" / "dune_gm_command.py",
        GM_CATALOG_PATH,
    ]
    extra = os.environ.get("DUNE_ADMIN_SELF_RELOAD_PATHS", "")
    for raw in extra.split(":"):
        raw = raw.strip()
        if raw:
            paths.append(pathlib.Path(raw).expanduser())
    return paths


def admin_panel_file_signature(path):
    try:
        stat = path.stat()
    except OSError:
        return None
    return (int(stat.st_mtime_ns), int(stat.st_size))


def admin_panel_source_signature(paths):
    return {str(path): admin_panel_file_signature(path) for path in paths}


def start_admin_panel_self_reload(server):
    if not ADMIN_PANEL_SELF_RELOAD_ENABLED:
        return

    watched = admin_panel_reload_paths()
    baseline = admin_panel_source_signature(watched)

    def watcher():
        nonlocal baseline
        while not ADMIN_PANEL_RESTART_EVENT.wait(ADMIN_PANEL_SELF_RELOAD_POLL_SECONDS):
            current = admin_panel_source_signature(watched)
            if (DEPLOYMENT_ASSURANCE_ROOT / "apply.lock").is_file():
                baseline = current
                continue
            if current == baseline:
                continue
            changed = [path for path, signature in current.items() if baseline.get(path) != signature]
            print(f"admin-panel source changed; self-reloading: {', '.join(changed)}", flush=True)
            time.sleep(max(0.0, ADMIN_PANEL_SELF_RELOAD_DEBOUNCE_SECONDS))
            ADMIN_PANEL_RESTART_EVENT.set()
            threading.Thread(target=server.shutdown, daemon=True).start()
            return

    threading.Thread(target=watcher, name="admin-panel-self-reload", daemon=True).start()
