def discovery_surface_dir():
    primary = ROOT / "research" / "surfaces"
    if primary.exists():
        return primary
    return CODE_ROOT / "research" / "surfaces"


def load_discovery_surfaces():
    surface_dir = discovery_surface_dir()
    entries = []
    errors = []
    if not surface_dir.exists():
        return {"surfaceDir": str(surface_dir), "entries": [], "errors": [f"surface directory not found: {surface_dir}"]}
    for path in sorted(surface_dir.glob("*.jsonl")):
        try:
            lines = path.read_text(encoding="utf-8").splitlines()
        except OSError as exc:
            errors.append(f"{path}: {exc}")
            continue
        for lineno, line in enumerate(lines, 1):
            if not line.strip() or line.lstrip().startswith("#"):
                continue
            try:
                row = json.loads(line)
            except json.JSONDecodeError as exc:
                errors.append(f"{path}:{lineno}: {exc}")
                continue
            row.setdefault("sourceFile", str(path.relative_to(ROOT) if str(path).startswith(str(ROOT)) else path))
            row.setdefault("sourceLine", lineno)
            entries.append(row)
    entries.sort(key=lambda item: item.get("id", ""))
    return {"surfaceDir": str(surface_dir), "entries": entries, "errors": errors}


def discovery_bucket(entry):
    if entry.get("status") in ("validated", "admin-safe") and entry.get("validated"):
        return "ready-or-promoted"
    if entry.get("surface") == "binary-candidate":
        return "needs-startup-parse-test"
    if entry.get("surface") in ("rmq-command", "server-command"):
        return "needs-contract-capture"
    if entry.get("status") in ("loadable", "observable"):
        return "needs-runtime-effect-test"
    return "needs-triage"


def discovery_queue_payload():
    payload = load_discovery_surfaces()
    buckets = {}
    for entry in payload["entries"]:
        buckets.setdefault(discovery_bucket(entry), []).append(entry)
    return {"ok": not payload["errors"], "buckets": buckets, "errors": payload["errors"], "surfaceDir": payload["surfaceDir"]}


def discovery_builds_payload():
    roots = [ROOT / "build", CODE_ROOT / "build"]
    builds = []
    seen = set()
    for root in roots:
        if not root.exists():
            continue
        for path in sorted(item for item in root.iterdir() if item.is_dir()):
            if path.name in seen:
                continue
            seen.add(path.name)
            files = sorted(item.name for item in path.iterdir() if item.is_file())
            builds.append({"build": path.name, "path": str(path), "files": files})
    return {"ok": True, "builds": builds}


def discovery_payload():
    surfaces = load_discovery_surfaces()
    return {
        "ok": not surfaces["errors"],
        "surfaces": surfaces["entries"],
        "surfaceDir": surfaces["surfaceDir"],
        "errors": surfaces["errors"],
        "queue": discovery_queue_payload()["buckets"],
        "builds": discovery_builds_payload()["builds"],
    }


def read_event_state():
    if not EVENT_STATE_FILE.exists():
        return {"events": [], "runs": [], "lastRun": None}
    try:
        state = json.loads(EVENT_STATE_FILE.read_text(encoding="utf-8"))
    except (OSError, json.JSONDecodeError):
        return {"events": [], "runs": [], "lastRun": None}
    if not isinstance(state, dict):
        return {"events": [], "runs": [], "lastRun": None}
    state.setdefault("events", [])
    state.setdefault("runs", [])
    state.setdefault("lastRun", None)
    return state


def write_event_state(state):
    BACKUP_ROOT.mkdir(parents=True, exist_ok=True)
    tmp = EVENT_STATE_FILE.with_suffix(".json.tmp")
    tmp.write_text(json.dumps(state, indent=2, sort_keys=True, default=json_default), encoding="utf-8")
    tmp.replace(EVENT_STATE_FILE)


def event_action_plan(action):
    kind = str(action.get("type", "")).strip()
    if kind == "announcement":
        return {"type": kind, "endpoint": "/api/ops/announcement", "payload": {"message": action.get("message", ""), "delay": action.get("delay", "immediate"), "repeat_seconds": int(action.get("repeat_seconds", 0) or 0)}, "safePrimitive": True}
    if kind == "restart":
        return {"type": kind, "endpoint": "/api/ops/restart", "payload": {"target": action.get("target", "deep-desert"), "action": action.get("action", "restart"), "delay": action.get("delay", "immediate"), "execute": False}, "safePrimitive": True}
    if kind == "typed-knob-plan":
        return {"type": kind, "endpoint": "/api/settings/typed-knobs", "payload": {"updates": action.get("updates", {})}, "safePrimitive": True, "dryRunOnly": True}
    if kind == "economy-bundle":
        return {"type": kind, "endpoint": "/api/admin/bundle", "payload": dict(action.get("payload", {}), dry_run=True), "safePrimitive": True, "dryRunOnly": True}
    if kind == "spice-cap-proposal":
        return {"type": kind, "endpoint": "/api/settings/typed-knobs", "payload": {"updates": {"spiceDeepDesertCaps": action.get("caps", {})}}, "safePrimitive": True, "dryRunOnly": True}
    raise ValueError(f"unsupported event action type: {kind}")


def build_event(body):
    actions = body.get("actions", [])
    if not isinstance(actions, list) or not actions:
        raise ValueError("actions must be a non-empty list")
    plans = [event_action_plan(action) for action in actions]
    run_at = str(body.get("runAt", body.get("run_at", ""))).strip() or None
    repeat_seconds = int(body.get("repeatSeconds", body.get("repeat_seconds", 0)) or 0)
    if repeat_seconds and not 60 <= repeat_seconds <= 365 * 86400:
        raise ValueError("repeatSeconds must be 0 or between 60 and 31536000")
    max_runs = int(body.get("maxRuns", body.get("max_runs", 1 if not repeat_seconds else 0)) or 0)
    if not 0 <= max_runs <= 10000:
        raise ValueError("maxRuns must be between 0 and 10000; 0 means unlimited")
    if run_at:
        event_parse_time(run_at)
    return {
        "id": secrets.token_hex(8),
        "name": str(body.get("name", "admin event")).strip()[:120] or "admin event",
        "status": "scheduled",
        "createdAt": time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime()),
        "runAt": run_at,
        "nextRunAt": run_at,
        "repeatSeconds": repeat_seconds,
        "maxRuns": max_runs,
        "runCount": 0,
        "actions": actions,
        "plan": plans,
    }


def event_dry_run(body):
    event = build_event(body)
    event["status"] = "dry-run"
    return {"ok": True, "dryRun": True, "event": event, "executionEnabled": EVENT_EXECUTION_ENABLED}


def create_event(body):
    event = build_event(body)
    with EVENT_LOCK:
        state = read_event_state()
        state["events"].append(event)
        write_event_state(state)
    return event


def cancel_event(event_id):
    with EVENT_LOCK:
        state = read_event_state()
        cancelled = 0
        for event in state.get("events", []):
            if event.get("id") == event_id and event.get("status") == "scheduled":
                event["status"] = "cancelled"
                event["cancelledAt"] = time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())
                cancelled += 1
        write_event_state(state)
    return {"ok": True, "cancelled": cancelled}


def event_parse_time(value):
    text = str(value or "").strip()
    if not text:
        raise ValueError("event time is required")
    if text.endswith("Z"):
        text = text[:-1] + "+00:00"
    parsed = datetime.datetime.fromisoformat(text)
    if parsed.tzinfo is None:
        parsed = parsed.replace(tzinfo=datetime.timezone.utc)
    return parsed.astimezone(datetime.timezone.utc)


def event_time(value):
    return event_parse_time(value).timestamp()


def execute_event(event_id, trigger="manual"):
    if not EVENT_EXECUTION_ENABLED:
        raise PermissionError("event execution is disabled; set DUNE_ADMIN_EVENT_EXECUTION_ENABLED=true")
    with EVENT_LOCK:
        state = read_event_state()
        event = next((item for item in state.get("events", []) if item.get("id") == event_id), None)
        if not event:
            raise ValueError("event not found")
        if event.get("status") != "scheduled":
            raise ValueError("event is not scheduled")
        run_id = secrets.token_hex(12)
        started_at = time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())
        executed = []
        failures = []
        for plan in event.get("plan", []):
            if plan.get("dryRunOnly"):
                executed.append({"type": plan.get("type"), "ok": True, "dryRun": True, "notes": "plan-only action, no write executed"})
            elif plan.get("type") == "announcement":
                try:
                    job = schedule_announcement(plan.get("payload") or {})
                    executed.append({"type": "announcement", "ok": True, "jobId": job.get("id")})
                except Exception as exc:
                    failures.append({"type": "announcement", "ok": False, "error": str(exc)[:500]})
            elif plan.get("type") == "restart":
                try:
                    payload = dict(plan.get("payload") or {})
                    payload["execute"] = False
                    job = schedule_restart(payload)
                    executed.append({"type": "restart", "ok": True, "jobId": job.get("id"), "execute": False})
                except Exception as exc:
                    failures.append({"type": "restart", "ok": False, "error": str(exc)[:500]})
            else:
                failures.append({"type": plan.get("type"), "ok": False, "error": "unsupported event execution primitive"})
        event["runCount"] = int(event.get("runCount") or 0) + 1
        event["lastRunAt"] = started_at
        repeat_seconds = int(event.get("repeatSeconds") or 0)
        max_runs = int(event.get("maxRuns") or 0)
        repeats_left = repeat_seconds and (max_runs == 0 or event["runCount"] < max_runs)
        if not failures and repeats_left:
            base = event_time(event.get("nextRunAt") or started_at)
            next_time = max(base + repeat_seconds, time.time() + 1)
            event["nextRunAt"] = time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime(next_time))
            event["status"] = "scheduled"
        else:
            event["nextRunAt"] = None
            event["status"] = "failed" if failures else "executed"
        run = {
            "id": run_id,
            "eventId": event_id,
            "eventName": event.get("name"),
            "trigger": str(trigger)[:40],
            "startedAt": started_at,
            "status": "failed" if failures else "executed",
            "executed": executed,
            "failures": failures,
            "runNumber": event["runCount"],
            "nextRunAt": event.get("nextRunAt"),
        }
        state["runs"] = (state.get("runs") or [])[-499:] + [run]
        state["lastRun"] = run
        write_event_state(state)
    audit_event("event-run", ok=not failures, event_id=event_id, run_id=run_id, trigger=trigger, executed=executed, failures=failures, next_run_at=event.get("nextRunAt"))
    return {"ok": not failures, "eventId": event_id, "runId": run_id, "executed": executed, "failures": failures, "nextRunAt": event.get("nextRunAt")}


def due_event_ids(now=None):
    now = time.time() if now is None else float(now)
    with EVENT_LOCK:
        state = read_event_state()
        return [
            event.get("id")
            for event in state.get("events", [])
            if event.get("status") == "scheduled"
            and event.get("nextRunAt")
            and event_time(event.get("nextRunAt")) <= now
        ]


def event_scheduler_worker():
    while True:
        if EVENT_EXECUTION_ENABLED:
            try:
                for event_id in due_event_ids():
                    execute_event(event_id, trigger="schedule")
            except Exception as exc:
                audit_event("event-scheduler", ok=False, error=str(exc)[:500])
        time.sleep(5)


def ensure_event_scheduler_thread():
    if getattr(ensure_event_scheduler_thread, "started", False):
        return
    ensure_event_scheduler_thread.started = True
    threading.Thread(target=event_scheduler_worker, name="event-scheduler-worker", daemon=True).start()


def gm_payload_preview(body):
    command = str(body.get("command", "")).strip()
    args = str(body.get("args", "")).strip()
    target_player = str(body.get("target_player", body.get("targetPlayer", ""))).strip()
    route = str(body.get("route", "")).strip() or "Survival_11"
    admin_player = str(body.get("admin_player", body.get("adminPlayer", ""))).strip()
    mode = str(body.get("mode", "")).strip() or os.environ.get("DUNE_GM_COMMAND_ENVELOPE_MODE", "service-message")
    allowed = set(GM_ALLOWED_COMMANDS) | set(GM_ALLOWED_GM_COMMANDS) | {f"CheatScript {name}" for name in GM_CHEAT_SCRIPTS}
    if command not in allowed and not command.startswith("CheatScript "):
        raise ValueError("command is not in the discovered allow-list")
    text = " ".join(part for part in (command, args) if part)
    envelope = build_envelope(mode, text, target_player=target_player, admin_player=admin_player)
    return {
        "ok": True,
        "dryRun": True,
        "route": {"exchange": "rpc", "routingKey": route},
        "targetPlayer": target_player,
        "adminPlayer": admin_player,
        "mode": mode,
        "commandText": text,
        "blocked": True,
        "reason": "Native command execution is blocked until UDuneServerCommandSubsystem RabbitMQ payload format is verified.",
        "payload": envelope,
    }


def gm_payload_execute(body):
    preview = gm_payload_preview(body)
    route = preview["route"]["routingKey"]
    if os.environ.get("DUNE_GM_COMMAND_TRANSPORT", "amqp") == "management":
        result = publish_command_management(
            preview["commandText"],
            route,
            target_player=preview["targetPlayer"],
            admin_player=preview["adminPlayer"],
            mode=preview["mode"],
            exchange=preview["route"]["exchange"],
        )
    else:
        result = publish_command(
            preview["commandText"],
            route,
            target_player=preview["targetPlayer"],
            admin_player=preview["adminPlayer"],
            mode=preview["mode"],
            exchange=preview["route"]["exchange"],
            app_id="DASH-Admin-Panel",
        )
    result["dryRun"] = False
    return result


def bool_env(name, default=False):
    value = os.environ.get(name, "true" if default else "false").lower()
    return value in ("1", "true", "yes", "on")


def player_disconnect_command_name():
    command = os.environ.get("DUNE_PLAYER_DISCONNECT_COMMAND", "RemoveSessionMember").strip()
    allowed = {"RemoveSessionMember", "KickLobbyMember"}
    if bool_env("DUNE_PLAYER_DISCONNECT_ALLOW_BATTLEYE", False):
        allowed.add("BattlEyeMegaKick")
    if command not in allowed:
        raise ValueError(f"DUNE_PLAYER_DISCONNECT_COMMAND must be one of: {', '.join(sorted(allowed))}")
    return command


def maintenance_player_disconnect_enabled():
    return GM_COMMANDS_ENABLED and GM_COMMAND_PAYLOAD_VERIFIED and bool_env("DUNE_CHAT_COMMAND_EXECUTE_PLAYER_DISCONNECT", False)


def online_players_for_restart(job):
    broad_targets = {"all", "core", "service-layer", "game-all"}
    services = set(job.get("services") or [])
    rows = query("""
        select ps.account_id, ps.character_name, ps.server_id, fs.map
        from dune.player_state ps
        left join dune.farm_state fs on fs.server_id = ps.server_id
        where ps.online_status::text = 'Online'
          and ps.character_name is not null
          and ps.server_id is not null
        order by ps.character_name
    """)
    if not services or job.get("target") in broad_targets:
        return rows
    return [
        row for row in rows
        if not row.get("map") or map_name_to_service(row.get("map")) in services
    ]


def map_name_to_service(map_name):
    normalized = str(map_name or "").strip().lower().replace("_", "-")
    aliases = {
        "haggabasin": "survival",
        "survival": "survival",
        "overmap": "overmap",
        "arrakeen": "arrakeen",
        "harko-village": "harko-village",
        "deep-desert": "deep-desert",
    }
    return aliases.get(normalized, normalized)


def disconnect_player_for_restart(player):
    command = player_disconnect_command_name()
    character_name = str(player.get("character_name") or "").strip()
    route = str(player.get("server_id") or "").strip()
    if not character_name or not route:
        return {"ok": False, "player": character_name, "route": route, "error": "missing character name or route"}
    command_text = f"{command} {character_name}"
    if os.environ.get("DUNE_GM_COMMAND_TRANSPORT", "amqp") == "management":
        result = publish_command_management(command_text, route, target_player=character_name, admin_player="DASH")
    else:
        result = publish_command(command_text, route, target_player=character_name, admin_player="DASH", app_id="DASH-Maintenance")
    return {
        "ok": bool(result.get("ok")),
        "player": character_name,
        "route": route,
        "map": player.get("map"),
        "commandText": command_text,
        "correlationId": result.get("correlationId"),
        "transport": result.get("transport"),
    }


def soft_disconnect_online_players(job):
    players = online_players_for_restart(job)
    result = {
        "ok": True,
        "enabled": maintenance_player_disconnect_enabled(),
        "waitSeconds": RESTART_DISCONNECT_WAIT_SECONDS,
        "players": [{"characterName": row.get("character_name"), "serverId": row.get("server_id"), "map": row.get("map")} for row in players],
        "sent": [],
        "errors": [],
    }
    if not players:
        result["skipped"] = "no online players in restart target"
        return result
    if not result["enabled"]:
        result["ok"] = False
        result["error"] = "online players are present, but targeted disconnect is gated; set DUNE_ADMIN_GM_COMMANDS_ENABLED=true, DUNE_GM_COMMAND_PAYLOAD_VERIFIED=true, and DUNE_CHAT_COMMAND_EXECUTE_PLAYER_DISCONNECT=true"
        return result
    max_workers = max(1, min(16, len(players)))
    with concurrent.futures.ThreadPoolExecutor(max_workers=max_workers) as executor:
        future_map = {executor.submit(disconnect_player_for_restart, player): player for player in players}
        for future in concurrent.futures.as_completed(future_map):
            player = future_map[future]
            try:
                sent = future.result()
            except Exception as exc:
                sent = {"ok": False, "player": player.get("character_name"), "route": player.get("server_id"), "error": str(exc)}
            if sent.get("ok"):
                result["sent"].append(sent)
            else:
                result["errors"].append(sent)
    if result["errors"]:
        result["ok"] = False
        result["error"] = "one or more soft disconnect publishes failed"
        return result
    time.sleep(max(0, RESTART_DISCONNECT_WAIT_SECONDS))
    result["waited"] = True
    return result


def read_director_transfer_settings():
    values = {key: meta["default"] for key, meta in DIRECTOR_TRANSFER_SETTINGS.items()}
    path = ALLOWED_CONFIGS["director.ini"]
    if not path.exists():
        return values
    in_battlegroup = False
    for raw_line in path.read_text(encoding="utf-8").splitlines():
        line = raw_line.strip()
        if not line:
            continue
        if line.startswith("[") and line.endswith("]"):
            in_battlegroup = line.strip("[]").strip().lower() == "battlegroup"
            continue
        if not in_battlegroup or "=" not in raw_line:
            continue
        key, value = raw_line.split("=", 1)
        key = key.strip()
        if key in DIRECTOR_TRANSFER_SETTINGS:
            text = strip_ini_comment(value)
            if DIRECTOR_TRANSFER_SETTINGS[key]["type"] == "ruleset":
                text = DIRECTOR_TRANSFER_RULESET_VALUES.get(text, text)
            values[key] = text
    return values


def validate_director_transfer_settings(updates):
    validated = {}
    for key, value in updates.items():
        if key not in DIRECTOR_TRANSFER_SETTINGS:
            continue
        meta = DIRECTOR_TRANSFER_SETTINGS[key]
        text = str(value).strip()
        if meta["type"] == "bool":
            lowered = text.lower()
            if lowered not in ("true", "false"):
                raise ValueError(f"{key} must be true or false")
            validated[key] = lowered
        elif meta["type"] == "int":
            try:
                number = int(text)
            except ValueError as exc:
                raise ValueError(f"{key} must be an integer") from exc
            if number < 0:
                raise ValueError(f"{key} must be >= 0")
            validated[key] = str(number)
        elif meta["type"] == "ruleset":
            text = DIRECTOR_TRANSFER_RULESET_VALUES.get(text, text)
            if text not in DIRECTOR_TRANSFER_RULESETS:
                labels = ", ".join(f"{value}={DIRECTOR_TRANSFER_RULESET_LABELS[value]}" for value in DIRECTOR_TRANSFER_RULESETS)
                raise ValueError(f"{key} must be one of: {labels}")
            validated[key] = text
    return validated


def write_director_transfer_settings(updates):
    path = ALLOWED_CONFIGS["director.ini"]
    values = read_director_transfer_settings()
    values.update(validate_director_transfer_settings(updates))
    original = path.read_text(encoding="utf-8").splitlines() if path.exists() else []
    rendered = []
    seen = set()
    in_battlegroup = False
    inserted = False

    def append_missing():
        nonlocal inserted
        if inserted:
            return
        for key in DIRECTOR_TRANSFER_SETTINGS:
            if key in seen:
                continue
            rendered.append(f"{key}={values.get(key, DIRECTOR_TRANSFER_SETTINGS[key]['default'])}")
            seen.add(key)
        inserted = True

    for raw_line in original:
        stripped = raw_line.strip()
        if stripped.startswith("[") and stripped.endswith("]"):
            if in_battlegroup:
                append_missing()
            in_battlegroup = stripped.strip("[]").strip().lower() == "battlegroup"
            rendered.append(raw_line)
            continue
        if in_battlegroup and "=" in raw_line:
            key, _ = raw_line.split("=", 1)
            key = key.strip()
            if key in DIRECTOR_TRANSFER_SETTINGS:
                rendered.append(f"{key}={values.get(key, DIRECTOR_TRANSFER_SETTINGS[key]['default'])}")
                seen.add(key)
                continue
        rendered.append(raw_line)

    if not original:
        rendered.extend(["[ Battlegroup ]"])
        in_battlegroup = True
    if in_battlegroup:
        append_missing()
    elif not inserted:
        if rendered and rendered[-1].strip():
            rendered.append("")
        rendered.append("[ Battlegroup ]")
        append_missing()

    backup_file(path)
    path.write_text("\n".join(rendered) + "\n", encoding="utf-8")


def read_player_online_state_settings():
    values = {key: meta["default"] for key, meta in PLAYER_ONLINE_STATE_SETTINGS.items()}
    path = ALLOWED_CONFIGS["UserGame.ini"]
    if not path.exists():
        return values
    in_section = False
    target_header = f"[{PLAYER_ONLINE_STATE_SECTION}]".lower()
    for raw_line in path.read_text(encoding="utf-8").splitlines():
        line = raw_line.strip()
        if not line:
            continue
        if line.startswith("[") and line.endswith("]"):
            in_section = line.lower() == target_header
            continue
        if not in_section or "=" not in raw_line:
            continue
        key, value = raw_line.split("=", 1)
        key = key.strip()
        if key in PLAYER_ONLINE_STATE_SETTINGS:
            values[key] = strip_ini_comment(value)
    return values


def validate_player_online_state_settings(updates):
    validated = {}
    for key, value in updates.items():
        if key not in PLAYER_ONLINE_STATE_SETTINGS:
            continue
        try:
            number = int(str(value).strip())
        except ValueError as exc:
            raise ValueError(f"{key} must be an integer") from exc
        if number < 0:
            raise ValueError(f"{key} must be >= 0")
        if number > 86400:
            raise ValueError(f"{key} must be <= 86400")
        validated[key] = str(number)
    return validated


def write_player_online_state_settings(updates):
    path = ALLOWED_CONFIGS["UserGame.ini"]
    values = read_player_online_state_settings()
    values.update(validate_player_online_state_settings(updates))
    original = path.read_text(encoding="utf-8").splitlines() if path.exists() else []
    rendered = []
    seen = set()
    in_section = False
    inserted = False
    target_header = f"[{PLAYER_ONLINE_STATE_SECTION}]".lower()

    def append_missing():
        nonlocal inserted
        if inserted:
            return
        for key in PLAYER_ONLINE_STATE_SETTINGS:
            if key in seen:
                continue
            rendered.append(f"{key}={values.get(key, PLAYER_ONLINE_STATE_SETTINGS[key]['default'])}")
            seen.add(key)
        inserted = True

    for raw_line in original:
        stripped = raw_line.strip()
        if stripped.startswith("[") and stripped.endswith("]"):
            if in_section:
                append_missing()
            in_section = stripped.lower() == target_header
            rendered.append(raw_line)
            continue
        if in_section and "=" in raw_line:
            key, _ = raw_line.split("=", 1)
            key = key.strip()
            if key in PLAYER_ONLINE_STATE_SETTINGS:
                rendered.append(f"{key}={values.get(key, PLAYER_ONLINE_STATE_SETTINGS[key]['default'])}")
                seen.add(key)
                continue
        rendered.append(raw_line)

    if not original:
        rendered.append(f"[{PLAYER_ONLINE_STATE_SECTION}]")
        in_section = True
    if in_section:
        append_missing()
    elif not inserted:
        if rendered and rendered[-1].strip():
            rendered.append("")
        rendered.append(f"[{PLAYER_ONLINE_STATE_SECTION}]")
        append_missing()

    backup_file(path)
    path.write_text("\n".join(rendered) + "\n", encoding="utf-8")


def parse_body(handler, max_bytes=MAX_BODY_BYTES):
    cached = getattr(handler, "_parsed_body", None)
    if cached is not None:
        return cached
    length = validate_body_framing(handler, max_bytes=max_bytes)
    data = handler.rfile.read(length) if length else b"{}"
    content_type = handler.headers.get("Content-Type", "")
    if "application/json" in content_type:
        body = json.loads(data.decode("utf-8") or "{}")
        if not isinstance(body, dict):
            raise ValueError("JSON request body must be an object")
        handler._parsed_body = body
        return body
    parsed = urllib.parse.parse_qs(data.decode("utf-8"), keep_blank_values=True)
    body = {key: values[-1] if values else "" for key, values in parsed.items()}
    handler._parsed_body = body
    return body


def validate_body_framing(handler, max_bytes=MAX_BODY_BYTES):
    if handler.headers.get("Transfer-Encoding"):
        raise ValueError("transfer-encoding is not supported")
    content_lengths = handler.headers.get_all("Content-Length", [])
    if len(content_lengths) > 1:
        raise ValueError("multiple content-length headers are not supported")
    try:
        length = int(content_lengths[0]) if content_lengths else 0
    except ValueError as exc:
        raise ValueError("invalid content-length") from exc
    if length < 0:
        raise ValueError("invalid content-length")
    if length > max_bytes:
        raise ValueError("request body too large")
    return length


def validate_json_post(handler, max_bytes=MAX_BODY_BYTES):
    length = validate_body_framing(handler, max_bytes=max_bytes)
    content_type = handler.headers.get("Content-Type", "")
    if content_type and "application/json" not in content_type.lower():
        raise ValueError("POST requests must use application/json")
    if length and not content_type:
        raise ValueError("POST requests must use application/json")
    return length


def require_confirmation(body, phrase):
    if str(body.get("confirm", "")).strip() != phrase:
        raise PermissionError(f"confirmation required: {phrase}")


def query(sql, params=None):
    with db_connect() as conn:
        with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cursor:
            cursor.execute(sql, params or ())
            if cursor.description:
                return list(cursor.fetchall())
            return []


def backup_inventory(limit=200):
    limit = max(1, min(int(limit), 500))
    if not BACKUPS_ROOT.exists():
        return {"root": str(BACKUPS_ROOT), "sets": [], "artifacts": []}
    sets = []
    artifacts = []
    for current_root, dir_names, file_names in os.walk(BACKUPS_ROOT):
        current = pathlib.Path(current_root)
        relative = current.relative_to(BACKUPS_ROOT)
        depth = len(relative.parts)
        if depth >= 4:
            dir_names[:] = []
        if current == BACKUP_ROOT:
            dir_names[:] = [name for name in dir_names if name == "maintenance"]
        file_set = set(file_names)
        looks_like_set = bool(file_set.intersection({"manifest.txt", "manifest.json", "backup-manifest.json"}))
        looks_like_set = looks_like_set or any(name.endswith((".dump", ".dump.gz")) for name in file_names)
        if current != BACKUPS_ROOT and looks_like_set:
            stat = current.stat()
            sets.append({
                "path": relative.as_posix(),
                "modifiedAt": datetime.datetime.fromtimestamp(stat.st_mtime, datetime.timezone.utc).isoformat(),
                "files": len(file_names),
                "manifest": next((name for name in ("manifest.txt", "manifest.json", "backup-manifest.json") if name in file_set), ""),
                "verifiable": (ROOT / "scripts" / "verify-backup.sh").exists(),
            })
    if BACKUP_ROOT.exists():
        for path in BACKUP_ROOT.iterdir():
            if not path.is_file() or path.name.startswith("."):
                continue
            stat = path.stat()
            artifacts.append({
                "path": path.relative_to(BACKUPS_ROOT).as_posix(),
                "sizeBytes": stat.st_size,
                "modifiedAt": datetime.datetime.fromtimestamp(stat.st_mtime, datetime.timezone.utc).isoformat(),
            })
    sets.sort(key=lambda row: row["modifiedAt"], reverse=True)
    artifacts.sort(key=lambda row: row["modifiedAt"], reverse=True)
    return {"root": str(BACKUPS_ROOT), "sets": sets[:limit], "artifacts": artifacts[:limit]}


def backup_archive_encryption_status():
    recipient = (os.environ.get("DUNE_BACKUP_GPG_RECIPIENT") or env_file_value("DUNE_BACKUP_GPG_RECIPIENT") or "").strip()
    enabled = env_bool("DUNE_BACKUP_ARCHIVE_ENCRYPTION_ENABLED", False)
    encrypted_root = BACKUPS_ROOT / "encrypted"
    archives = sorted(encrypted_root.glob("*.tar.gz.gpg"), key=lambda path: path.stat().st_mtime, reverse=True)[:100] if encrypted_root.is_dir() else []
    return {
        "enabled": enabled,
        "configured": enabled and bool(re.fullmatch(r"(?:[A-Fa-f0-9]{40}|[A-Fa-f0-9]{64})", recipient)),
        "recipientConfigured": bool(recipient),
        "recipientSuffix": recipient[-16:].upper() if len(recipient) >= 16 else "",
        "requireVerifiedBackup": (os.environ.get("DUNE_BACKUP_GPG_REQUIRE_VERIFY") or env_file_value("DUNE_BACKUP_GPG_REQUIRE_VERIFY") or "true").lower() in ("1", "true", "yes", "on"),
        "encryptedArchives": [{"path": str(path.relative_to(BACKUPS_ROOT)), "sizeBytes": path.stat().st_size, "receipt": path.with_suffix(path.suffix + ".json").is_file()} for path in archives],
        "hostCommand": "scripts/encrypt-backup-archive.sh --env-file .env backups/<verified-set>",
        "decryptCommand": "scripts/decrypt-backup-archive.sh --env-file .env backups/encrypted/<archive>.tar.gz.gpg",
        "automaticRestore": False,
        "format": "OpenPGP",
    }


def resolve_backup_set(relative_path):
    raw = str(relative_path or "").strip()
    if not raw or pathlib.PurePosixPath(raw).is_absolute():
        raise ValueError("backup path must be relative to backups/")
    resolved = (BACKUPS_ROOT / raw).resolve()
    try:
        resolved.relative_to(BACKUPS_ROOT.resolve())
    except ValueError as exc:
        raise ValueError("backup path escapes backups/") from exc
    if not resolved.is_dir():
        raise ValueError("backup set directory does not exist")
    return resolved


def verify_backup_set(relative_path):
    path = resolve_backup_set(relative_path)
    verifier = ROOT / "scripts" / "verify-backup.sh"
    if not verifier.exists():
        raise FileNotFoundError("scripts/verify-backup.sh is unavailable")
    bash = shutil.which("bash")
    if bash:
        completed = subprocess.run(
            [bash, str(verifier), str(path)],
            cwd=ROOT,
            text=True,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            timeout=180,
            check=False,
        )
        ok = completed.returncode == 0
        exit_code = completed.returncode
        stdout = completed.stdout
        stderr = completed.stderr
    else:
        ok, stdout, stderr = verify_backup_set_native(path)
        exit_code = 0 if ok else 1
    return {
        "ok": ok,
        "path": path.relative_to(BACKUPS_ROOT).as_posix(),
        "exitCode": exit_code,
        "stdout": stdout[-256 * 1024:],
        "stderr": stderr[-256 * 1024:],
    }


def verify_backup_set_native(path):
    """Structural verifier for the minimal admin image, which has no bash."""
    output = []
    errors = []
    dumps = sorted(path.glob("*.dump"))
    archives = sorted(path.glob("*.tgz"))
    maintenance = path / "maintenance"
    if maintenance.is_dir():
        dumps.extend(sorted(maintenance.glob("*/*.dump")))
        archives.extend(sorted(maintenance.glob("*/*.tgz")))
    if not dumps:
        errors.append(f"FAIL no Postgres dump files found under {path}")
    pg_restore = shutil.which("pg_restore")
    for dump in dumps:
        if not pg_restore:
            output.append(f"SKIP pg_restore not available for {dump}")
            continue
        completed = subprocess.run(
            [pg_restore, "--list", str(dump)], cwd=ROOT, text=True,
            stdout=subprocess.DEVNULL, stderr=subprocess.PIPE, timeout=180, check=False,
        )
        if completed.returncode == 0:
            output.append(f"OK dump {dump}")
        else:
            errors.append(f"FAIL dump {dump}: {completed.stderr.strip()}")
    for archive in archives:
        try:
            with tarfile.open(archive, "r:gz") as handle:
                handle.getmembers()
            output.append(f"OK archive {archive}")
        except (OSError, tarfile.TarError) as exc:
            errors.append(f"FAIL archive {archive}: {exc}")
    for name in ("community-rewards.sqlite3", "moderation.sqlite3", "base-gallery.sqlite3", "operational-slo.sqlite3", "capacity-intelligence.sqlite3", "desired-state.sqlite3", "change-intelligence.sqlite3"):
        database = path / name
        if not database.is_file():
            output.append(f"WARN no {name} found in {path}")
            continue
        try:
            connection = sqlite3.connect(f"file:{database}?mode=ro", uri=True)
            try:
                integrity = connection.execute("pragma integrity_check").fetchone()[0]
            finally:
                connection.close()
            if integrity != "ok":
                raise ValueError(integrity)
            output.append(f"OK SQLite snapshot {database}")
        except (sqlite3.Error, ValueError) as exc:
            errors.append(f"FAIL SQLite snapshot {database}: {exc}")
    capacity_database = path / "capacity-intelligence.sqlite3"
    if capacity_database.is_file():
        capacity_check = capacity_intelligence.Store(capacity_database, CAPACITY_INTELLIGENCE_POLICY).verify()
        if capacity_check.get("ok"):
            output.append(f"OK capacity application receipts {capacity_database}")
        else:
            errors.append(f"FAIL capacity application receipts {capacity_database}: {capacity_check}")
    desired_database = path / "desired-state.sqlite3"
    if desired_database.is_file():
        archive = next((candidate for candidate in (path / "config.tgz", path / "config-and-env.tgz") if candidate.is_file()), None)
        if archive is None:
            errors.append(f"FAIL desired-state HMAC verification requires matching config archive in {path}")
        else:
            try:
                with tarfile.open(archive, "r:gz") as handle, tempfile.TemporaryDirectory(prefix="dash-desired-verify-") as directory:
                    material = {}
                    for name, maximum in (("config/desired-state.json", 1024 * 1024), ("config/secrets/desired-state-hmac.secret", 16 * 1024)):
                        member = handle.getmember(name)
                        if not member.isfile() or member.size <= 0 or member.size > maximum:
                            raise ValueError(f"invalid desired-state backup member: {name}")
                        extracted = handle.extractfile(member)
                        if extracted is None:
                            raise ValueError(f"unreadable desired-state backup member: {name}")
                        material[name] = extracted.read(maximum + 1)
                        if len(material[name]) > maximum:
                            raise ValueError(f"oversized desired-state backup member: {name}")
                    verify_root = pathlib.Path(directory)
                    policy = verify_root / "desired-state.json"
                    secret = verify_root / "desired-state-hmac.secret"
                    policy.write_bytes(material["config/desired-state.json"])
                    secret.write_bytes(material["config/secrets/desired-state-hmac.secret"])
                    os.chmod(policy, 0o600)
                    os.chmod(secret, 0o600)
                    desired_check = desired_state.Store(desired_database, policy, secret).verify()
                if desired_check.get("ok"):
                    output.append(f"OK desired-state backup-bound HMAC attestations {desired_database}")
                else:
                    errors.append(f"FAIL desired-state HMAC attestations {desired_database}: {desired_check}")
            except (OSError, KeyError, ValueError, tarfile.TarError) as exc:
                errors.append(f"FAIL desired-state matching policy/HMAC material in {archive}: {exc}")
    change_database = path / "change-intelligence.sqlite3"
    if change_database.is_file():
        archive = next((candidate for candidate in (path / "config.tgz", path / "config-and-env.tgz") if candidate.is_file()), None)
        if archive is None:
            errors.append(f"FAIL change-intelligence HMAC verification requires matching config archive in {path}")
        else:
            try:
                with tarfile.open(archive, "r:gz") as handle, tempfile.TemporaryDirectory(prefix="dash-change-verify-") as directory:
                    material = {}
                    for name, maximum in (("config/change-intelligence.json", 1024 * 1024), ("config/secrets/change-intelligence-hmac.secret", 16 * 1024)):
                        member = handle.getmember(name)
                        if not member.isfile() or member.size <= 0 or member.size > maximum:
                            raise ValueError(f"invalid change-intelligence backup member: {name}")
                        extracted = handle.extractfile(member)
                        if extracted is None:
                            raise ValueError(f"unreadable change-intelligence backup member: {name}")
                        material[name] = extracted.read(maximum + 1)
                        if len(material[name]) > maximum:
                            raise ValueError(f"oversized change-intelligence backup member: {name}")
                    verify_root = pathlib.Path(directory)
                    policy = verify_root / "change-intelligence.json"
                    secret = verify_root / "change-intelligence-hmac.secret"
                    policy.write_bytes(material["config/change-intelligence.json"])
                    secret.write_bytes(material["config/secrets/change-intelligence-hmac.secret"])
                    os.chmod(policy, 0o600)
                    os.chmod(secret, 0o600)
                    change_check = change_intelligence.Store(change_database, policy, secret).verify()
                if change_check.get("ok"):
                    output.append(f"OK change-intelligence backup-bound HMAC event chain {change_database}")
                else:
                    errors.append(f"FAIL change-intelligence HMAC event chain {change_database}: {change_check}")
            except (OSError, KeyError, ValueError, tarfile.TarError) as exc:
                errors.append(f"FAIL change-intelligence matching policy/HMAC material in {archive}: {exc}")
    audit_database = path / "audit-ledger.sqlite3"
    audit_key = path / "audit-ledger.hmac.key"
    audit_anchor = path / "audit-ledger.anchor.json"
    audit_artifacts = sum(candidate.is_file() for candidate in (audit_database, audit_key, audit_anchor))
    if audit_artifacts == 3:
        try:
            audit_check = audit_ledger.Store(
                audit_database, key_path=audit_key, anchor_path=audit_anchor
            ).verify()
            if audit_check.get("ok"):
                output.append(f"OK audit ledger backup-bound HMAC chain and authenticated head {audit_database}")
            else:
                errors.append(f"FAIL audit ledger backup-bound HMAC chain and authenticated head {audit_database}: {audit_check}")
        except (OSError, RuntimeError, sqlite3.Error, ValueError) as exc:
            errors.append(f"FAIL audit ledger backup-bound HMAC chain and authenticated head {audit_database}: {exc}")
    elif audit_artifacts:
        errors.append("FAIL audit ledger backup requires database, HMAC key, and authenticated anchor together")
    else:
        output.append(f"WARN no audit-ledger snapshot found in {path}")
    evidence_archive = path / "operator-evidence.tgz"
    if evidence_archive.is_file():
        archive = next((candidate for candidate in (path / "config.tgz", path / "config-and-env.tgz") if candidate.is_file()), None)
        if archive is None:
            errors.append(f"FAIL portable signed operator evidence verification requires matching config archive in {path}")
        else:
            try:
                with tarfile.open(archive, "r:gz") as handle, tempfile.TemporaryDirectory(prefix="dash-evidence-verify-") as directory:
                    member = handle.getmember("config/secrets/change-intelligence-hmac.secret")
                    if not member.isfile() or member.size <= 0 or member.size > 16 * 1024:
                        raise ValueError("invalid change-intelligence key backup member")
                    extracted = handle.extractfile(member)
                    if extracted is None:
                        raise ValueError("unreadable change-intelligence key backup member")
                    secret = pathlib.Path(directory) / "change-intelligence-hmac.secret"
                    secret.write_bytes(extracted.read(16 * 1024 + 1))
                    os.chmod(secret, 0o600)
                    evidence_check = verify_operator_evidence_archive(evidence_archive, secret)
                output.append(f"OK {evidence_check['files']} portable signed operator evidence capsule(s) {evidence_archive}")
            except (OSError, KeyError, ValueError, json.JSONDecodeError, tarfile.TarError) as exc:
                errors.append(f"FAIL portable signed operator evidence capsules or matching HMAC key {evidence_archive}: {exc}")
    else:
        output.append(f"WARN no operator-evidence.tgz found in {path}")
    manifest_json = path / "manifest.json"
    manifest_text = path / "manifest.txt"
    try:
        if manifest_json.is_file():
            json.loads(manifest_json.read_text(encoding="utf-8"))
            output.append(f"OK manifest {manifest_json}")
        elif manifest_text.is_file():
            manifest_text.read_text(encoding="utf-8")
            output.append(f"OK manifest {manifest_text}")
        else:
            output.append(f"WARN no manifest found in {path}")
    except (OSError, json.JSONDecodeError) as exc:
        errors.append(f"FAIL manifest in {path}: {exc}")
    if errors:
        errors.append("backup verification complete: FAILED")
    else:
        output.append("backup verification complete: OK")
    return not errors, "\n".join(output) + "\n", "\n".join(errors) + ("\n" if errors else "")


def run_backup_command(args, timeout=1800):
    completed = subprocess.run(
        [str(value) for value in args], cwd=ROOT, env=os.environ.copy(), text=True,
        stdout=subprocess.PIPE, stderr=subprocess.PIPE, timeout=timeout, check=False,
    )
    result = {
        "ok": completed.returncode == 0,
        "exitCode": completed.returncode,
        "stdout": completed.stdout[-256 * 1024:],
        "stderr": completed.stderr[-256 * 1024:],
    }
    if completed.returncode != 0:
        raise RuntimeError((completed.stderr or completed.stdout or f"backup command exited {completed.returncode}")[-4000:])
    return result


def create_full_backup():
    result = create_maintenance_backup({"id": f"browser-{secrets.token_hex(4)}", "action": "backup", "target": "all", "services": []})
    path = pathlib.Path(result["path"])
    relative = path.relative_to(BACKUPS_ROOT).as_posix()
    verified = verify_backup_set(relative)
    if not verified.get("ok"):
        raise RuntimeError("new backup failed verification")
    return {"ok": True, "path": relative, "backup": result, "verification": verified}


def default_backup_schedule():
    return {"enabled": False, "time": "05:00", "intervalHours": 24, "retentionDays": 0, "nextRun": None, "lastRun": None, "lastResult": None, "runs": []}


def read_backup_schedule():
    state = read_care_package_state(BACKUP_SCHEDULE_FILE, default_backup_schedule())
    return {**default_backup_schedule(), **state}


def write_backup_schedule(state):
    write_care_package_state(BACKUP_SCHEDULE_FILE, state)


def next_backup_schedule_time(clock_text, now=None):
    match = re.fullmatch(r"([01]\d|2[0-3]):([0-5]\d)", str(clock_text or ""))
    if not match:
        raise ValueError("backup time must use HH:MM in 24-hour local time")
    now = now or datetime.datetime.now().astimezone()
    candidate = now.replace(hour=int(match.group(1)), minute=int(match.group(2)), second=0, microsecond=0)
    if candidate <= now:
        candidate += datetime.timedelta(days=1)
    return candidate.timestamp()


def configure_backup_schedule(body):
    enabled = str(body.get("enabled", "false")).lower() in ("1", "true", "yes", "on")
    clock_text = str(body.get("time", "05:00")).strip()
    interval_hours = int(body.get("interval_hours", body.get("intervalHours", 24)) or 24)
    retention_days = int(body.get("retention_days", body.get("retentionDays", 0)) or 0)
    if not 1 <= interval_hours <= 24 * 31:
        raise ValueError("interval_hours must be between 1 and 744")
    if not 0 <= retention_days <= 3650:
        raise ValueError("retention_days must be between 0 and 3650")
    next_run = next_backup_schedule_time(clock_text) if enabled else None
    with BACKUP_SCHEDULE_LOCK:
        state = read_backup_schedule()
        state.update({"enabled": enabled, "time": clock_text, "intervalHours": interval_hours, "retentionDays": retention_days, "nextRun": next_run})
        write_backup_schedule(state)
    return backup_schedule_public_state(state)


def backup_schedule_public_state(state=None):
    state = state or read_backup_schedule()
    result = dict(state)
    for key in ("nextRun", "lastRun"):
        result[key + "Iso"] = datetime.datetime.fromtimestamp(result[key], datetime.timezone.utc).isoformat() if result.get(key) else None
    result["mutationEnabled"] = BACKUP_MUTATIONS_ENABLED
    return result


def prune_scheduled_backups(state, now=None):
    retention_days = int(state.get("retentionDays") or 0)
    if retention_days <= 0:
        return []
    cutoff = (now or time.time()) - retention_days * 86400
    removed = []
    retained = []
    maintenance_root = (BACKUP_ROOT / "maintenance").resolve()
    for run in state.get("runs") or []:
        path = (BACKUPS_ROOT / str(run.get("path") or "")).resolve()
        if float(run.get("createdAt") or 0) < cutoff and path != maintenance_root and maintenance_root in path.parents and path.exists():
            shutil.rmtree(path)
            removed.append(str(run.get("path")))
        else:
            retained.append(run)
    state["runs"] = retained[-200:]
    return removed


def backup_schedule_tick(now=None):
    now = now or time.time()
    with BACKUP_SCHEDULE_LOCK:
        state = read_backup_schedule()
        if not state.get("enabled") or not state.get("nextRun") or now < float(state["nextRun"]):
            return backup_schedule_public_state(state)
        state["nextRun"] = now + int(state.get("intervalHours") or 24) * 3600
        write_backup_schedule(state)
    try:
        result = create_full_backup()
        run = {"createdAt": now, "path": result["path"], "ok": True}
        last_result = {"ok": True, "path": result["path"], "verification": result.get("verification")}
    except Exception as exc:
        run = {"createdAt": now, "ok": False, "error": str(exc)}
        last_result = {"ok": False, "error": str(exc)}
    with BACKUP_SCHEDULE_LOCK:
        state = read_backup_schedule()
        state["lastRun"] = now
        state["lastResult"] = last_result
        state.setdefault("runs", []).append(run)
        removed = prune_scheduled_backups(state, now)
        if removed:
            state["lastPruned"] = removed
        write_backup_schedule(state)
    return backup_schedule_public_state(state)


def backup_schedule_worker():
    while True:
        try:
            if MUTATIONS_ENABLED and BACKUP_MUTATIONS_ENABLED:
                backup_schedule_tick()
        except Exception as exc:
            with BACKUP_SCHEDULE_LOCK:
                state = read_backup_schedule()
                state["lastResult"] = {"ok": False, "error": str(exc)}
                write_backup_schedule(state)
        time.sleep(30)


def ensure_backup_schedule_thread():
    global BACKUP_SCHEDULE_THREAD_STARTED
    if BACKUP_SCHEDULE_THREAD_STARTED:
        return
    BACKUP_SCHEDULE_THREAD_STARTED = True
    threading.Thread(target=backup_schedule_worker, name="backup-schedule-worker", daemon=True).start()


def restore_drill_configuration():
    host_workspace = os.environ.get("DUNE_RESTORE_DRILL_HOST_WORKSPACE") or os.environ.get("DUNE_RESTART_HOST_WORKSPACE") or ""
    return {
        "hostWorkspaceConfigured": bool(host_workspace and pathlib.Path(host_workspace).is_absolute()),
        "hostWorkspace": host_workspace,
        "dockerSocket": os.environ.get("DUNE_RESTORE_DRILL_DOCKER_SOCKET", DOCKER_SOCKET),
        "image": os.environ.get("DUNE_RESTORE_DRILL_IMAGE", restore_drill.DEFAULT_IMAGE),
        "maxBackupAgeHours": max(1.0, min(float(os.environ.get("DUNE_RESTORE_DRILL_MAX_BACKUP_AGE_HOURS", "36")), 24 * 365)),
        "maxRestoreSeconds": max(30, min(int(os.environ.get("DUNE_RESTORE_DRILL_MAX_RESTORE_SECONDS", "900")), 24 * 3600)),
        "memoryMiB": max(256, min(int(os.environ.get("DUNE_RESTORE_DRILL_MEMORY_MIB", "2048")), 65536)),
        "pgdataMiB": max(256, min(int(os.environ.get("DUNE_RESTORE_DRILL_PGDATA_MIB", "1536")), 65536)),
        "cpus": max(0.25, min(float(os.environ.get("DUNE_RESTORE_DRILL_CPUS", "2")), 64.0)),
        "pidsLimit": max(32, min(int(os.environ.get("DUNE_RESTORE_DRILL_PIDS_LIMIT", "128")), 4096)),
        "runUid": int(os.environ.get("DUNE_HOST_UID", "1000")),
        "runGid": int(os.environ.get("DUNE_HOST_GID", "1000")),
        "receiptRetention": max(10, min(int(os.environ.get("DUNE_RESTORE_DRILL_RECEIPT_RETENTION", "1000")), 100000)),
    }


def restore_drill_public_status():
    result = restore_drill.status(RESTORE_DRILL_RECEIPT_ROOT, limit=20)
    with RESTORE_DRILL_RUNTIME_LOCK:
        runtime = dict(RESTORE_DRILL_RUNTIME)
    config = restore_drill_configuration()
    result.update({
        "featureEnabled": RESTORE_DRILL_ENABLED,
        "executionEnabled": MUTATIONS_ENABLED and RESTORE_DRILL_EXECUTION_ENABLED,
        "requiredCapability": "infrastructure.write",
        "confirm": CONFIRM_RESTORE_DRILL,
        "runtime": runtime,
        "policy": {
            "maxBackupAgeHours": config["maxBackupAgeHours"],
            "maxRestoreSeconds": config["maxRestoreSeconds"],
        },
        "resources": {
            "memoryMiB": config["memoryMiB"], "pgdataMiB": config["pgdataMiB"],
            "cpus": config["cpus"], "pidsLimit": config["pidsLimit"],
        },
        "isolationContract": {
            "network": "none", "liveDatabaseTouched": False, "readOnlyRootfs": True,
            "capabilitiesDropped": ["ALL"], "noNewPrivileges": True,
            "privateStagingCopy": True, "sourceBindReadOnly": True,
            "sourceMode": "0400", "sourceSha256Verified": True,
            "ephemeralPgdata": True,
        },
        "ready": bool(RESTORE_DRILL_ENABLED and config["hostWorkspaceConfigured"] and pathlib.Path(config["dockerSocket"]).exists()),
    })
    return result


def queue_restore_drill(source=None):
    if not RESTORE_DRILL_ENABLED:
        raise PermissionError("restore drills are disabled; set DUNE_RESTORE_DRILL_ENABLED=true")
    config = restore_drill_configuration()
    if not config["hostWorkspaceConfigured"]:
        raise RuntimeError("DUNE_RESTORE_DRILL_HOST_WORKSPACE or DUNE_RESTART_HOST_WORKSPACE must be an absolute host path")
    if not pathlib.Path(config["dockerSocket"]).exists():
        raise RuntimeError(f"Docker socket not found: {config['dockerSocket']}")
    with RESTORE_DRILL_RUNTIME_LOCK:
        if RESTORE_DRILL_RUNTIME["running"]:
            raise RuntimeError("a restore drill is already running")
        RESTORE_DRILL_RUNTIME.update({
            "running": True, "queuedAt": time.time(), "startedAt": None,
            "finishedAt": None, "lastResult": None, "lastError": None,
        })

    def worker():
        with RESTORE_DRILL_RUNTIME_LOCK:
            RESTORE_DRILL_RUNTIME["startedAt"] = time.time()
        try:
            result = restore_drill.run_drill(
                ROOT,
                host_workspace=config["hostWorkspace"],
                source=source or None,
                receipt_root=RESTORE_DRILL_RECEIPT_ROOT,
                docker_socket=config["dockerSocket"],
                image=config["image"],
                max_backup_age_seconds=config["maxBackupAgeHours"] * 3600,
                max_restore_seconds=config["maxRestoreSeconds"],
                memory_bytes=config["memoryMiB"] * 1024**2,
                pgdata_bytes=config["pgdataMiB"] * 1024**2,
                cpu_count=config["cpus"],
                pids_limit=config["pidsLimit"],
                run_uid=config["runUid"], run_gid=config["runGid"],
                retention_count=config["receiptRetention"],
            )
            with RESTORE_DRILL_RUNTIME_LOCK:
                RESTORE_DRILL_RUNTIME["lastResult"] = result
            audit_event(
                "backup-restore-drill-finished", ok=result.get("ok"),
                receipt=result.get("receiptPath"), source=result.get("sourcePath"),
                integrity_ok=result.get("integrityOk"), policy_ok=result.get("policyOk"),
                restore_seconds=(result.get("timings") or {}).get("restoreSeconds"),
            )
        except Exception as exc:
            with RESTORE_DRILL_RUNTIME_LOCK:
                RESTORE_DRILL_RUNTIME["lastError"] = str(exc)
            audit_event("backup-restore-drill-finished", ok=False, error=str(exc))
        finally:
            with RESTORE_DRILL_RUNTIME_LOCK:
                RESTORE_DRILL_RUNTIME["running"] = False
                RESTORE_DRILL_RUNTIME["finishedAt"] = time.time()

    threading.Thread(target=worker, name="backup-restore-drill", daemon=True).start()
    return {"ok": True, "queued": True, "status": restore_drill_public_status()}


def operational_slo_store():
    global OPERATIONAL_SLO_STORE
    with OPERATIONAL_SLO_STORE_LOCK:
        if OPERATIONAL_SLO_STORE is None:
            OPERATIONAL_SLO_STORE = operational_slo.Store(
                OPERATIONAL_SLO_DATABASE,
                OPERATIONAL_SLO_POLICY,
                owner_uid=os.environ.get("DUNE_HOST_UID"),
                owner_gid=os.environ.get("DUNE_HOST_GID"),
            )
            OPERATIONAL_SLO_STORE.initialize()
        return OPERATIONAL_SLO_STORE


def _slo_latest_backup():
    selected = restore_drill.select_dump(ROOT)
    stat_result = selected.stat()
    return {
        "path": selected.relative_to(ROOT).as_posix(),
        "modifiedAtEpoch": stat_result.st_mtime,
        "ageSeconds": max(0.0, time.time() - stat_result.st_mtime),
        "bytes": stat_result.st_size,
    }


def _slo_restore_proof():
    state = restore_drill.status(RESTORE_DRILL_RECEIPT_ROOT, limit=1)
    latest = state.get("latest") or {}
    finished = str(latest.get("finishedAt") or "")
    if finished.endswith("Z"):
        finished = finished[:-1] + "+00:00"
    try:
        finished_epoch = datetime.datetime.fromisoformat(finished).timestamp()
    except (TypeError, ValueError):
        finished_epoch = 0.0
    age = max(0.0, time.time() - finished_epoch) if finished_epoch else None
    return {
        "id": latest.get("id"),
        "ok": bool(latest.get("ok")),
        "integrityOk": bool(latest.get("integrityOk")),
        "policyOk": bool(latest.get("policyOk")),
        "receiptHashValid": bool(latest.get("receiptHashValid")),
        "ageSeconds": age,
        "restoreSeconds": (latest.get("timings") or {}).get("restoreSeconds"),
        "liveDatabaseTouched": latest.get("liveDatabaseTouched"),
    }


def collect_operational_slo_signals():
    collected = time.time()
    errors = {}
    context = {"collectedAtEpoch": collected}
    try:
        database_ready = bool(query("select to_regnamespace('dune') is not null as ready")[0].get("ready"))
    except Exception as exc:
        database_ready = False
        errors["database"] = str(exc)[:1000]
    try:
        inventory = {row["service"]: row for row in docker_service_inventory()}
        required_control = ("postgres", "director", "gateway", "admin-rmq", "game-rmq", "text-router")
        control_states = {service: (inventory.get(service) or {}).get("state", "missing") for service in required_control}
        control_plane_ready = all(state == "running" for state in control_states.values())
        context["controlPlane"] = control_states
    except Exception as exc:
        control_plane_ready = False
        errors["controlPlane"] = str(exc)[:1000]
    try:
        required_maps = restart_online_snapshot()
        required_maps_ready = bool(required_maps.get("ok"))
        context["requiredMaps"] = required_maps
    except Exception as exc:
        required_maps_ready = False
        errors["requiredMaps"] = str(exc)[:1000]
    try:
        backup = _slo_latest_backup()
        backup_rpo_ready = backup["ageSeconds"] <= OPERATIONAL_SLO_BACKUP_MAX_AGE_HOURS * 3600
        context["backup"] = backup
    except Exception as exc:
        backup_rpo_ready = False
        errors["backup"] = str(exc)[:1000]
    try:
        proof = _slo_restore_proof()
        proof_age_ready = proof["ageSeconds"] is not None and proof["ageSeconds"] <= OPERATIONAL_SLO_RESTORE_PROOF_MAX_AGE_HOURS * 3600
        restore_proof_ready = bool(
            proof["ok"] and proof["integrityOk"] and proof["policyOk"] and
            proof["receiptHashValid"] and proof_age_ready and proof["liveDatabaseTouched"] is False
        )
        context["restoreProof"] = proof
    except Exception as exc:
        restore_proof_ready = False
        errors["restoreProof"] = str(exc)[:1000]
    memory = read_meminfo()
    available = int(memory.get("availableBytes") or 0)
    memory_headroom_ready = available >= int(OPERATIONAL_SLO_MEMORY_FLOOR_GIB * 1024 ** 3)
    context["memory"] = {
        "availableBytes": available,
        "floorBytes": int(OPERATIONAL_SLO_MEMORY_FLOOR_GIB * 1024 ** 3),
        "totalBytes": int(memory.get("totalBytes") or 0),
    }
    token_required = ADMIN_REQUIRE_TOKEN
    credential_ready = bool(ADMIN_TOKEN and ADMIN_TOKEN != "change-me-admin-token") or bool(RBAC_ENABLED and ADMIN_ACCESS_FILE.exists())
    admin_auth_ready = token_required and credential_ready
    context["adminAuth"] = {"tokenRequired": token_required, "credentialSourceConfigured": credential_ready, "rbacEnabled": RBAC_ENABLED, "mode": "authenticated" if token_required else "unlocked"}
    try:
        desired_status = desired_state_store().status(limit=20) if DESIRED_STATE_ENABLED else {"state": "disabled", "sealed": False, "openFindings": []}
        desired_state_attested = bool(desired_status.get("sealed") and desired_status.get("state") == "attested" and desired_status.get("integrity", {}).get("ok"))
        context["desiredState"] = {
            "state": desired_status.get("state"),
            "sealed": desired_status.get("sealed"),
            "openFindings": len(desired_status.get("openFindings") or []),
            "integrityOk": bool(desired_status.get("integrity", {}).get("ok")),
        }
    except Exception as exc:
        desired_state_attested = False
        errors["desiredState"] = str(exc)[:1000]
    try:
        change_integrity = change_intelligence_store().verify() if CHANGE_INTELLIGENCE_ENABLED else {"ok": False, "state": "disabled"}
        change_intelligence_ready = bool(change_integrity.get("ok"))
        context["changeIntelligence"] = {
            "enabled": CHANGE_INTELLIGENCE_ENABLED,
            "integrityOk": change_intelligence_ready,
            "eventCount": change_integrity.get("eventCount", 0),
        }
    except Exception as exc:
        change_intelligence_ready = False
        errors["changeIntelligence"] = str(exc)[:1000]
    context["errors"] = errors
    return {
        "signals": {
            "database_ready": database_ready,
            "control_plane_ready": control_plane_ready,
            "required_maps_ready": required_maps_ready,
            "backup_rpo_ready": backup_rpo_ready,
            "restore_proof_ready": restore_proof_ready,
            "memory_headroom_ready": memory_headroom_ready,
            "admin_auth_ready": admin_auth_ready,
            "desired_state_attested": desired_state_attested,
            "change_intelligence_ready": change_intelligence_ready,
        },
        "context": context,
    }


def operational_slo_tick():
    OPERATIONAL_SLO_RUNTIME["running"] = True
    try:
        collected = collect_operational_slo_signals()
        result = operational_slo_store().record(collected["signals"], context=collected["context"])
        OPERATIONAL_SLO_RUNTIME.update({"lastSampleAt": time.time(), "lastResult": result, "lastError": ""})
        for incident_id in result.get("incidentsOpened") or []:
            objective_id = incident_id[4:].rsplit("-", 1)[0] if str(incident_id).startswith("slo-") else "unknown"
            audit_event("slo-incident-opened", ok=False, incident_id=incident_id, objective_id=objective_id)
        for incident_id in result.get("incidentsResolved") or []:
            objective_id = incident_id[4:].rsplit("-", 1)[0] if str(incident_id).startswith("slo-") else "unknown"
            audit_event("slo-incident-resolved", ok=True, incident_id=incident_id, objective_id=objective_id)
        return result
    except Exception as exc:
        OPERATIONAL_SLO_RUNTIME.update({"lastError": str(exc)[:2000]})
        raise
    finally:
        OPERATIONAL_SLO_RUNTIME["running"] = False


def operational_slo_public_status():
    if not OPERATIONAL_SLO_ENABLED:
        return {"ok": False, "overall": "disabled", "enabled": False, "mutationEnabled": False, "runtime": dict(OPERATIONAL_SLO_RUNTIME)}
    result = operational_slo_store().status(limit=200)
    result.update({
        "enabled": True,
        "mutationEnabled": MUTATIONS_ENABLED and OPERATIONAL_SLO_MUTATIONS_ENABLED,
        "runtime": dict(OPERATIONAL_SLO_RUNTIME),
        "confirmIncident": CONFIRM_SLO_INCIDENT,
        "confirmMaintenance": CONFIRM_SLO_MAINTENANCE,
        "requiredCapability": "infrastructure.write",
        "integrity": operational_slo_store().integrity_check(),
        "pollSeconds": OPERATIONAL_SLO_POLL_SECONDS,
    })
    return result


def operational_slo_worker():
    while True:
        if OPERATIONAL_SLO_ENABLED:
            try:
                operational_slo_tick()
            except Exception:
                pass
        time.sleep(OPERATIONAL_SLO_POLL_SECONDS)


def ensure_operational_slo_thread():
    global OPERATIONAL_SLO_THREAD_STARTED
    if OPERATIONAL_SLO_THREAD_STARTED:
        return
    OPERATIONAL_SLO_THREAD_STARTED = True
    threading.Thread(target=operational_slo_worker, name="operational-slo-worker", daemon=True).start()


def capacity_intelligence_store():
    global CAPACITY_INTELLIGENCE_STORE
    with CAPACITY_INTELLIGENCE_STORE_LOCK:
        if CAPACITY_INTELLIGENCE_STORE is None:
            CAPACITY_INTELLIGENCE_STORE = capacity_intelligence.Store(
                CAPACITY_INTELLIGENCE_DATABASE,
                CAPACITY_INTELLIGENCE_POLICY,
                owner_uid=os.environ.get("DUNE_HOST_UID"),
                owner_gid=os.environ.get("DUNE_HOST_GID"),
            )
            CAPACITY_INTELLIGENCE_STORE.initialize()
        return CAPACITY_INTELLIGENCE_STORE


def collect_capacity_intelligence_maps():
    autoscaler = read_autoscaler_state()
    inventory = {row["service"]: row for row in docker_service_inventory() if row["service"] in GAME_MAP_SERVICES}
    counts = autoscaler_player_counts()
    readiness_rows = query("""
        select wp.partition_id,
          bool_or(wp.server_id is not null and coalesce(fs.alive,false) and coalesce(fs.ready,false)
            and asi.server_id is not null and not coalesce(wp.blocked,false)) as ready
        from dune.world_partition wp
        left join dune.farm_state fs on fs.server_id=wp.server_id
        left join dune.active_server_ids asi on asi.server_id=wp.server_id
        where wp.partition_id = any(%s)
        group by wp.partition_id
    """, (list(range(1, len(GAME_MAP_SERVICES) + 1)),))
    readiness = {}
    for row in readiness_rows:
        partition = int(row.get("partition_id") or 0)
        if 1 <= partition <= len(GAME_MAP_SERVICES):
            readiness[GAME_MAP_SERVICES[partition - 1]] = bool(row.get("ready"))
    now = time.time()
    maps = []
    for service in GAME_MAP_SERVICES:
        mode = autoscaler["modes"].get(service, "always-on")
        state = str(inventory.get(service, {}).get("state") or "missing").lower()
        players = int(counts.get(service, 0))
        demand_at = float(autoscaler["demand"].get(service) or 0)
        demanded = demand_at > 0 and now - demand_at <= autoscaler["demandTtlSeconds"]
        running = state == "running"
        maps.append({
            "service": service,
            "mode": mode,
            "state": state,
            "players": players,
            "demanded": demanded,
            "ready": bool(readiness.get(service, False)),
            "optionalWarm": running and mode == "dynamic" and players == 0 and not demanded,
            "retentionSeconds": autoscaler_retention_seconds(autoscaler, service),
        })
    return maps


def capacity_apply_recommendations(actor="system", source="manual"):
    store = capacity_intelligence_store()
    status = store.status()
    policy = status["policy"]
    changes = []
    with AUTOSCALER_LOCK:
        state = read_autoscaler_state()
        for service, recommendation in sorted(status.get("recommendations", {}).items()):
            if not recommendation.get("eligible") or state["modes"].get(service) != "dynamic":
                continue
            current = autoscaler_retention_seconds(state, service)
            target = int(recommendation["recommendedRetentionSeconds"])
            fraction = float(policy["maximumApplyFraction"])
            lower = max(int(policy["minimumRetentionSeconds"]), int(math.floor(current * (1.0 - fraction))))
            upper = min(int(policy["maximumRetentionSeconds"]), int(math.ceil(current * (1.0 + fraction))))
            applied = max(lower, min(target, upper))
            if applied == current:
                continue
            state["retentionByService"][service] = applied
            changes.append({
                "service": service,
                "beforeSeconds": current,
                "recommendedSeconds": target,
                "appliedSeconds": applied,
                "confidence": recommendation["confidence"],
                "revisitSamples": recommendation["revisitSamples"],
                "startSamples": recommendation["startSamples"],
            })
        if changes:
            state["profile"] = "adaptive"
            write_autoscaler_state(state)
    receipt = store.record_application(actor, source, changes) if changes else None
    return {
        "ok": True,
        "applied": bool(changes),
        "changes": changes,
        "receipt": receipt,
        "reason": "no eligible recommendation changed the current policy" if not changes else "bounded recommendations applied",
        "maximumApplyFraction": policy["maximumApplyFraction"],
    }


def capacity_intelligence_tick():
    CAPACITY_INTELLIGENCE_RUNTIME["running"] = True
    try:
        result = capacity_intelligence_store().observe(collect_capacity_intelligence_maps())
        auto_result = None
        if MUTATIONS_ENABLED and AUTOSCALER_MUTATIONS_ENABLED and CAPACITY_AUTO_APPLY_ENABLED:
            last = CAPACITY_INTELLIGENCE_RUNTIME.get("lastAutoApplyAt") or 0
            if time.time() - float(last) >= CAPACITY_AUTO_APPLY_INTERVAL_HOURS * 3600:
                auto_result = capacity_apply_recommendations(actor="system:capacity-intelligence", source="automatic")
                CAPACITY_INTELLIGENCE_RUNTIME.update({"lastAutoApplyAt": time.time(), "lastAutoApply": auto_result})
        CAPACITY_INTELLIGENCE_RUNTIME.update({"lastSampleAt": time.time(), "lastResult": result, "lastError": ""})
        return {**result, "autoApply": auto_result}
    except Exception as exc:
        CAPACITY_INTELLIGENCE_RUNTIME["lastError"] = str(exc)[:2000]
        raise
    finally:
        CAPACITY_INTELLIGENCE_RUNTIME["running"] = False


