    def command_console_operation(self, command_id):
        """Execute one exact read-only console operation without a subprocess."""
        if command_id == "landsraad-cycle":
            checked = gameplay_presets.validate_landsraad_cycle(CONFIG_ROOT)
            return {"ok": True, "weeklyCycleDays": 7, "checked": checked, "message": "Landsraad Coriolis guard OK: weekly cycle=7 days"}
        if command_id == "stack-status":
            health = self.ops_health()
            return {"ok": True, "summary": health.get("summary"), "verdicts": health.get("verdicts"), "services": docker_service_inventory()}
        if command_id == "rmq-health":
            services = {row["service"]: row for row in docker_service_inventory()}
            probes = [self.tcp_probe("admin-rmq", "admin-rmq", 5672), self.tcp_probe("game-rmq", "game-rmq", 5672)]
            return {"ok": all(row.get("ok") for row in probes), "probes": probes, "services": [services.get("admin-rmq"), services.get("game-rmq"), services.get("rmq-auth-shim"), services.get("text-router")]}
        if command_id == "inventory-audit":
            counts = query("""
                select
                  (select count(*) from (select 1 from dune.items group by inventory_id,position_index having count(*)>1) duplicate_slots)::int as duplicate_slots,
                  (select count(*) from dune.items where position_index<0)::int as negative_slots,
                  (select count(*) from dune.items i join dune.inventories inv on inv.id=i.inventory_id where inv.max_item_count>=0 and i.position_index>=inv.max_item_count)::int as over_capacity_items
            """)[0]
            return {"ok": not any(int(value or 0) for value in counts.values()), "readOnly": True, **counts}
        if command_id == "storage-status":
            disk = shutil.disk_usage(ROOT)
            backups = backup_inventory(50)
            return {"ok": True, "workspace": {"path": str(ROOT), "totalBytes": disk.total, "usedBytes": disk.used, "freeBytes": disk.free, "usedPercent": round(disk.used / disk.total * 100, 1) if disk.total else None}, "backupSetsReturned": len(backups.get("sets") or []), "backupRoot": str(BACKUPS_ROOT), "containers": docker_container_stats(live_stats=False)}
        if command_id == "cpu-affinity-status":
            rows = []
            for container in docker_project_containers():
                labels = container.get("Labels") or {}
                service = labels.get("com.docker.compose.service") or (container.get("Names") or [""])[0].lstrip("/")
                detail = docker_api(f"/containers/{container.get('Id')}/json")
                rows.append({"service": service, "state": container.get("State"), "cpusetCpus": (detail.get("HostConfig") or {}).get("CpusetCpus") or "unrestricted"})
            return {"ok": True, "composeProject": DOCKER_COMPOSE_PROJECT, "containers": sorted(rows, key=lambda row: row["service"])}
        raise ValueError("unknown command-console command id")

    def update_currency(self, body):
        controller_id = int(body["player_controller_id"])
        currency_id = int(body["currency_id"])
        amount = int(body["amount"])
        mode = body.get("mode", "add")
        if mode == "set":
            execute("""
                insert into dune.player_virtual_currency_balances(player_controller_id,currency_id,balance)
                values (%s,%s,%s)
                on conflict (player_controller_id,currency_id) do update set balance=excluded.balance
            """, (controller_id, currency_id, amount))
        elif mode == "add":
            execute("""
                insert into dune.player_virtual_currency_balances(player_controller_id,currency_id,balance)
                values (%s,%s,%s)
                on conflict (player_controller_id,currency_id) do update set balance=dune.player_virtual_currency_balances.balance + excluded.balance
            """, (controller_id, currency_id, amount))
        else:
            raise ValueError("mode must be add or set")

    def resolve_player_money_ids(self, body):
        controller_id = body.get("player_controller_id", body.get("controller_id", body.get("controllerId")))
        owner_id = body.get("owner_id", body.get("ownerId"))
        account_id = body.get("account_id", body.get("accountId"))
        character_name = str(body.get("character_name", body.get("characterName", ""))).strip()
        player = None
        if account_id not in ("", None) or character_name:
            player = self.resolve_player(account_id=account_id, character_name=character_name)
            controller_id = controller_id or player.get("player_controller_id")
            owner_id = owner_id or controller_id
        if controller_id in ("", None):
            raise ValueError("player_controller_id, account_id, or character_name is required")
        return {
            "controllerId": int(controller_id),
            "ownerId": int(owner_id) if owner_id not in ("", None) else int(controller_id),
            "accountId": int(player["account_id"]) if player and player.get("account_id") is not None else (int(account_id) if account_id not in ("", None) else None),
            "characterName": player.get("character_name") if player else character_name,
        }

    def grant_player_inventory_solari(self, body):
        ids = self.resolve_player_money_ids(body)
        amount = int(body.get("amount", 0))
        if amount <= 0:
            raise ValueError("amount must be > 0")
        dry_run = str(body.get("dry_run", body.get("dryRun", "true"))).lower() not in ("0", "false", "no", "off")
        inventory_body = dict(body)
        if not str(inventory_body.get("inventory_id", "")).strip():
            inventory_body.setdefault("inventory_type", 0)
        inventory_id = self.resolve_inventory_id(inventory_body)
        inventory = self.inventory_for_grant(inventory_id)
        max_count = inventory.get("max_item_count")
        if max_count is not None and max_count > 0:
            position_rows = query("""
                select slot.position_index
                from generate_series(0, %s - 1) as slot(position_index)
                where not exists (
                    select 1 from dune.items i
                    where i.inventory_id=%s and i.position_index=slot.position_index
                )
                order by slot.position_index
                limit 1
            """, (int(max_count), inventory_id))
        else:
            position_rows = query("select coalesce(max(position_index), -1) + 1 as position_index from dune.items where inventory_id=%s", (inventory_id,))
        if not position_rows:
            raise ValueError(f"no free inventory position inside inventory capacity {max_count}")
        position_index = int(position_rows[0]["position_index"])
        plan = {
            "function": "dune.save_item",
            "templateId": "SolarisCoin",
            "controllerId": ids["controllerId"],
            "inventoryId": inventory_id,
            "itemId": None,
            "action": "create-stack",
            "amount": amount,
            "beforeStack": 0,
            "afterStack": amount,
            "positionIndex": position_index,
            "rollback": {
                "endpoint": "/api/admin/item/delete",
                "item_id": None,
                "confirm": CONFIRM_DELETE_ITEM,
            },
            "warnings": self.item_grant_warnings(inventory, "SolarisCoin"),
        }
        if dry_run:
            return dict(ids, ok=True, dryRun=True, location="inventory", amount=amount, plan=plan, executionGate="DUNE_ADMIN_MUTATIONS_ENABLED", confirm=CONFIRM_SOLARI_GRANT)
        self.require_mutations()
        require_confirmation(body, CONFIRM_SOLARI_GRANT)
        item_body = dict(body)
        item_body.update({
            "inventory_id": inventory_id,
            "template_id": "SolarisCoin",
            "stack_size": amount,
            "quality_level": 0,
            "position_index": position_index,
            "stats": {},
            "dry_run": False,
        })
        item_id = int(self.grant_item(item_body)["item_id"])
        plan["rollback"]["item_id"] = item_id
        after = query("select id, inventory_id, stack_size, position_index, template_id from dune.items where id=%s", (item_id,))
        result = dict(ids, ok=True, dryRun=False, location="inventory", amount=amount, before=[], after=after, rollback=plan["rollback"], inventory_id=inventory_id, template_id="SolarisCoin", stack_size=amount)
        result["privateMessage"] = self.notify_grant_private_message(body, result, "SolarisCoin", amount)
        return result

    def grant_player_bank_solari(self, body):
        ids = self.resolve_player_money_ids(body)
        amount = int(body.get("amount", 0))
        if amount <= 0:
            raise ValueError("amount must be > 0")
        bank_body = dict(body)
        bank_body.update({
            "owner_id": ids["ownerId"],
            "controller_id": ids["controllerId"],
            "amount": amount,
            "mode": "add",
        })
        result = self.exchange_mutation(bank_body)
        result.update(dict(ids, location="bank", amount=amount))
        return result

    def update_xp(self, body):
        player_id = int(body["player_id"])
        track_type = str(body["track_type"])
        amount = int(body["amount"])
        level = float(body.get("level", 0))
        mode = body.get("mode", "add")
        if mode == "set":
            execute("select dune.set_specialization_xp_and_level(%s, %s::dune.specializationtracktype, %s, %s)", (player_id, track_type, amount, level))
        elif mode == "add":
            existing = query("select xp_amount, level from dune.specialization_tracks where player_id=%s and track_type::text=%s", (player_id, track_type))
            current_xp = existing[0]["xp_amount"] if existing else 0
            current_level = existing[0]["level"] if existing else level
            execute("select dune.set_specialization_xp_and_level(%s, %s::dune.specializationtracktype, %s, %s)", (player_id, track_type, current_xp + amount, current_level))
        else:
            raise ValueError("mode must be add or set")

    def purchase_keystone(self, body):
        player_id = int(body["player_id"])
        keystone = str(body["keystone"]).strip()
        result = query("select dune.purchase_specialization_keystone(%s, %s) as purchased", (player_id, keystone))[0]["purchased"]
        if not result:
            raise ValueError("keystone was not purchased; it may be unknown or already present")
        return {"ok": True, "player_id": player_id, "keystone": keystone}

    def reset_keystones(self, body):
        player_id = int(body["player_id"])
        execute("select dune.reset_specialization_keystones(%s)", (player_id,))

    def economy_bundle(self, body):
        dry_run = str(body.get("dry_run", body.get("dryRun", "true"))).lower() not in ("0", "false", "no", "off")
        plan = []
        for row in body.get("currency", []) or []:
            plan.append({"type": "currency", "payload": row, "statement": "insert/update dune.player_virtual_currency_balances"})
        for row in body.get("xp", []) or []:
            plan.append({"type": "xp", "payload": row, "statement": "select dune.set_specialization_xp_and_level(...)"})
        for row in body.get("items", []) or []:
            item_body = dict(row)
            item_body["dry_run"] = True
            try:
                preview = self.grant_item(item_body)
            except Exception as exc:
                preview = {"ok": False, "error": str(exc), "payload": item_body}
            plan.append({"type": "item", "payload": row, "preview": preview})
        if dry_run:
            return {"ok": True, "dryRun": True, "plan": plan, "executionGate": "DUNE_ADMIN_BUNDLE_MUTATIONS_ENABLED"}
        self.require_mutations()
        if not BUNDLE_MUTATIONS_ENABLED:
            raise PermissionError("bundle mutations are disabled; set DUNE_ADMIN_BUNDLE_MUTATIONS_ENABLED=true")
        require_confirmation(body, CONFIRM_BUNDLE_MUTATION)
        executed = []
        for row in body.get("currency", []) or []:
            self.update_currency(row)
            executed.append({"type": "currency", "ok": True})
        for row in body.get("xp", []) or []:
            self.update_xp(row)
            executed.append({"type": "xp", "ok": True})
        for row in body.get("items", []) or []:
            self.require_item_grants()
            item_body = dict(row)
            item_body["dry_run"] = False
            executed.append({"type": "item", "result": self.grant_item(item_body)})
        return {"ok": True, "dryRun": False, "plan": plan, "executed": executed}

    def care_package_grant(self, body):
        package_id = str(body.get("package_id", body.get("packageId", ""))).strip()
        account_id = int(body.get("account_id", body.get("accountId")))
        dry_run = str(body.get("dry_run", body.get("dryRun", "true"))).lower() not in ("0", "false", "no", "off")
        package = care_package_by_id(package_id)
        if not package:
            raise ValueError("care package id was not found")
        players = query("""
            select account_id, character_name, online_status::text,
                   player_controller_id, player_pawn_id
            from dune.player_state
            where account_id=%s
        """, (account_id,))
        if not players:
            raise ValueError("account_id not found")
        player = players[0]
        controller_id = player.get("player_controller_id")
        if controller_id in (None, "") and (package["currency"] or package["xp"]):
            raise ValueError("target player has no player_controller_id for currency or XP actions")

        previous = [
            row for row in care_package_history(1000)
            if row.get("ok") and row.get("packageId") == package_id and int(row.get("accountId") or 0) == account_id
        ]
        blockers = []
        if not package["enabled"]:
            blockers.append("package is disabled in config/care-packages.json")
        if package["oncePerAccount"] and previous:
            blockers.append("package is limited to one successful grant per account")
        cooldown_hours = int(package["cooldownHours"] or 0)
        if cooldown_hours and previous:
            try:
                latest = datetime.datetime.fromisoformat(str(previous[0].get("timestamp") or "").replace("Z", "+00:00"))
                eligible_at = latest + datetime.timedelta(hours=cooldown_hours)
                if datetime.datetime.now(datetime.timezone.utc) < eligible_at:
                    blockers.append(f"package cooldown is active until {eligible_at.isoformat()}")
            except ValueError:
                blockers.append("package history timestamp is invalid; refusing cooldown bypass")

        items = []
        for row in package["items"]:
            if not isinstance(row, dict):
                raise ValueError(f"care package {package_id} contains a non-object item action")
            item = dict(row)
            item.pop("inventory_id", None)
            item.pop("inventoryId", None)
            item["account_id"] = account_id
            items.append(item)
        currency = []
        for row in package["currency"]:
            if not isinstance(row, dict):
                raise ValueError(f"care package {package_id} contains a non-object currency action")
            action = dict(row)
            action["player_controller_id"] = int(controller_id)
            action.setdefault("mode", "add")
            currency.append(action)
        xp = []
        for row in package["xp"]:
            if not isinstance(row, dict):
                raise ValueError(f"care package {package_id} contains a non-object XP action")
            action = dict(row)
            action["player_id"] = int(controller_id)
            action.setdefault("mode", "add")
            xp.append(action)
        if not items and not currency and not xp:
            raise ValueError("care package has no item, currency, or XP actions")

        bundle = {"dry_run": dry_run, "items": items, "currency": currency, "xp": xp}
        preview = self.economy_bundle(dict(bundle, dry_run=True))
        result = {
            "ok": True,
            "dryRun": dry_run,
            "packageId": package_id,
            "accountId": account_id,
            "player": player,
            "package": package,
            "eligible": not blockers,
            "blockers": blockers,
            "previousSuccessfulGrants": len(previous),
            "bundle": preview,
            "executionGate": "DUNE_ADMIN_CARE_PACKAGES_ENABLED",
            "confirm": CONFIRM_CARE_PACKAGE_GRANT,
        }
        if dry_run:
            return result

        self.require_mutations()
        if not CARE_PACKAGES_ENABLED:
            raise PermissionError("care package grants are disabled; set DUNE_ADMIN_CARE_PACKAGES_ENABLED=true")
        if not BUNDLE_MUTATIONS_ENABLED:
            raise PermissionError("care package grants require DUNE_ADMIN_BUNDLE_MUTATIONS_ENABLED=true")
        require_confirmation(body, CONFIRM_CARE_PACKAGE_GRANT)
        if blockers:
            raise PermissionError("care package is not eligible: " + "; ".join(blockers))
        backup = create_db_backup()
        executed = self.economy_bundle(dict(bundle, dry_run=False, confirm=CONFIRM_BUNDLE_MUTATION))
        append_care_package_history({
            "ok": bool(executed.get("ok")),
            "status": "granted" if executed.get("ok") else "failed",
            "source": str(body.get("source") or "manual"),
            "ruleId": body.get("rule_id", body.get("ruleId")),
            "grantWhen": body.get("grant_when", body.get("grantWhen")),
            "packageId": package_id,
            "accountId": account_id,
            "characterName": player.get("character_name"),
            "backupPath": backup.get("path"),
            "actions": {"items": len(items), "currency": len(currency), "xp": len(xp)},
        })
        result.update({"dryRun": False, "backup": backup, "bundle": executed})
        return result

    def offline_player_recovery(self, body):
        account_id = int(body.get("account_id", body.get("accountId")))
        partition_id = int(body.get("partition_id", body.get("partitionId")))
        dry_run = str(body.get("dry_run", body.get("dryRun", "true"))).lower() not in ("0", "false", "no", "off")
        player = query("""
            select ps.account_id, ps.character_name, ps.online_status::text, ps.server_id,
                   ps.previous_server_partition_id, a.funcom_id, a."user" as fls_id
            from dune.player_state ps
            left join dune.accounts a on a.id = ps.account_id
            where ps.account_id=%s
        """, (account_id,))
        partition = query("select partition_id, server_id, map, dimension_index, label, blocked from dune.world_partition where partition_id=%s", (partition_id,))
        if not player:
            raise ValueError("account_id not found")
        if not partition:
            raise ValueError("partition_id not found")
        if str(player[0].get("online_status") or "").lower() == "online":
            raise ValueError("player is online; offline recovery refuses to move online players")
        location = body.get("location", body.get("target_location", body.get("targetLocation", {})))
        if not isinstance(location, dict):
            raise ValueError("location must be an object with x, y, and z")
        target_location = {
            "x": float(location.get("x", 0)),
            "y": float(location.get("y", 0)),
            "z": float(location.get("z", 0)),
        }
        fls_id = str(player[0].get("fls_id") or player[0].get("funcom_id") or "").strip()
        if not fls_id:
            raise ValueError("player account has no FLS/user id for offline player recovery")
        offline_check = query("select dune.is_player_offline(%s) as offline", (fls_id,))
        is_offline = bool(offline_check and offline_check[0].get("offline"))
        actor_snapshot = query("""
            select a.id as actor_id, a.class, a.map, a.partition_id, a.dimension_index,
                   ((a.transform).location).x as x,
                   ((a.transform).location).y as y,
                   ((a.transform).location).z as z
            from dune.player_state ps
            join dune.actors a
              on a.id in (ps.player_controller_id, ps.player_state_id, ps.player_pawn_id)
            where ps.account_id=%s
            order by a.id
        """, (account_id,))
        plan = {
            "function": "dune.admin_move_offline_player_to_partition",
            "args": [fls_id, partition_id, target_location],
            "player": player[0],
            "targetPartition": partition[0],
            "currentActors": actor_snapshot,
            "executable": is_offline,
            "blockers": [] if is_offline else ["dune.is_player_offline(fls_id) is false; wait for Offline before moving"],
            "note": "Strict-offline teleport uses the first-party pawn-row move helper. Online/network-timeout automation is intentionally separate and not hidden behind this endpoint.",
        }
        if dry_run:
            return {"ok": True, "dryRun": True, "accountId": account_id, "partitionId": partition_id, "plan": plan}
        self.require_mutations()
        require_confirmation(body, CONFIRM_PLAYER_RECOVERY)
        if not is_offline:
            raise ValueError("player is not fully Offline according to dune.is_player_offline")
        query("""
            select dune.admin_move_offline_player_to_partition(
                %s,
                %s,
                row(%s,%s,%s)::dune.vector
            )
        """, (
            fls_id,
            partition_id,
            target_location["x"], target_location["y"], target_location["z"],
        ))
        rows = query("""
            select a.id as actor_id, a.class, a.map, a.partition_id, a.dimension_index,
                   ((a.transform).location).x as x,
                   ((a.transform).location).y as y,
                   ((a.transform).location).z as z
            from dune.player_state ps
            join dune.actors a
              on a.id in (ps.player_controller_id, ps.player_state_id, ps.player_pawn_id)
            where ps.account_id=%s
            order by a.id
        """, (account_id,))
        return {
            "ok": True,
            "dryRun": False,
            "accountId": account_id,
            "partitionId": partition_id,
            "result": rows,
            "rollback": {
                "previousServerPartitionId": player[0].get("previous_server_partition_id"),
                "previousServerId": player[0].get("server_id"),
                "previousActors": actor_snapshot,
            },
        }

